    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_3: &str = "howtoplay.commandBlocks.text.3";
    #[doc = "You can set the name of the Command Block in the Hover Note field."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_4: &str = "howtoplay.commandBlocks.text.4";
    #[doc = "§eBlock Type§f - There are three types of Command Blocks, each with their own color and behavior:"]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_5: &str = "howtoplay.commandBlocks.text.5";
    #[doc = "§eImpulse§f - Only executes the stored command when the block receives a redstone signal."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_5_1: &str = "howtoplay.commandBlocks.text.5.1";
    #[doc = "§eChain§f - Executes the stored command when the Command Block behind it has or has not executed its command."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_5_2: &str = "howtoplay.commandBlocks.text.5.2";
    #[doc = "§eRepeat§f - Once activated, this Command Block will continue executing its stored command as long as it exists."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_5_3: &str = "howtoplay.commandBlocks.text.5.3";
    #[doc = "§eCondition§f - There are two conditions, each will affect the behavior of the Command Block:"]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_6: &str = "howtoplay.commandBlocks.text.6";
    #[doc = "§eUnconditional§f - Executes the stored command even if the Command Block behind it failed to execute its command."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_6_1: &str = "howtoplay.commandBlocks.text.6.1";
    #[doc = "§eConditional§f - Only executes the stored command if the Command Block behind it succeeded in executing its command."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_6_2: &str = "howtoplay.commandBlocks.text.6.2";
    #[doc = "§eRedstone§f - There are two redstone settings, each will affect the behavior of the Command Block:"]
