    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_7_1: &str = "howtoplay.commandBlocks.text.7.1";
    #[doc = "§eAlways Active§f - Does not require a redstone signal to activate."]
    pub const HOWTOPLAY_COMMANDBLOCKS_TEXT_7_2: &str = "howtoplay.commandBlocks.text.7.2";
