    #[doc = "Jigsaw Blocks"]
    pub const HOWTOPLAY_JIGSAWBLOCKS: &str = "howtoplay.jigsawBlocks";
    #[doc = "Jigsaw Blocks give creators the ability to generate large structures in the world by connecting multiple structure templates."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_1: &str = "howtoplay.jigsawBlocks.text.1";
    #[doc = "How to Obtain"]
    pub const HOWTOPLAY_JIGSAWBLOCKS_HEADER_1: &str = "howtoplay.jigsawBlocks.header.1";
    #[doc = "To get a Jigsaw Block you must use the /give slash command. To use a Jigsaw Block, you must have Operator permissions."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_2: &str = "howtoplay.jigsawBlocks.text.2";
    #[doc = "Settings"]
    pub const HOWTOPLAY_JIGSAWBLOCKS_HEADER_2: &str = "howtoplay.jigsawBlocks.header.2";
    #[doc = "Jigsaw Blocks have multiple settings that control how they join together to form a larger structure."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_3: &str = "howtoplay.jigsawBlocks.text.3";
    #[doc = "§eTarget Pool§f - The path of the template pool to search for a connecting structure template. The template pool should contain at least one structure that matches the Jigsaw's \"Target Name\" field."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_4: &str = "howtoplay.jigsawBlocks.text.4";
    #[doc = "§eName§f - The name of the Jigsaw. This is used when connecting from Jigsaws with a matching \"Target Name\"."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_5: &str = "howtoplay.jigsawBlocks.text.5";
    #[doc = "§eTurns Into§f - The type of block the Jigsaw Block will turn into when placed in the world during structure generation."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_6: &str = "howtoplay.jigsawBlocks.text.6";
    #[doc = "§eSelection Priority§f - When the parent piece is being processed for connections, this is the order in which this Jigsaw block attempts to connect to its target piece. Jigsaws will be processed in descending priority with random ordering breaking ties."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_7: &str = "howtoplay.jigsawBlocks.text.7";
    #[doc = "§ePlacement Priority§f - When this Jigsaw block connects to a piece, this is the order in which that piece is processed for connections in the wider structure. Pieces will be processed in descending priority with insertion order breaking ties."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_8: &str = "howtoplay.jigsawBlocks.text.8";
    #[doc = "§eJoint Type§f - A joint can be either Rollable (default) or Aligned. If the joint type is Rollable, the target structure will be rotated randomly around the source Jigsaw Block. If the joint type is Aligned, the target structure will be placed such that the rotation of the target Jigsaw Block aligns with the rotation of the source Jigsaw Block. Note that this only applies when the Jigsaw Block is placed facing up or down."]
    pub const HOWTOPLAY_JIGSAWBLOCKS_TEXT_9: &str = "howtoplay.jigsawBlocks.text.9";
