    #[doc = "Navigation"]
    pub const HOWTOPLAY_NAVIGATION: &str = "howtoplay.navigation";
    #[doc = "Navigation is an important skill that you will learn in Minecraft as it's not always easy to find your way home."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_1: &str = "howtoplay.navigation.text.1";
    #[doc = "First of all, there are some basic tools that you should know about."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_2: &str = "howtoplay.navigation.text.2";
    #[doc = "Navigation Tools"]
    pub const HOWTOPLAY_NAVIGATION_HEADER_1: &str = "howtoplay.navigation.header.1";
    #[doc = "A Compass will point in the direction of the first place you spawned into the world, an easy way to find where you started."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_3: &str = "howtoplay.navigation.text.3";
    #[doc = "A Map lets you see the area you've explored. Put it in your offhand slot to use it like a mini-map. You can increase its size by adding more paper to the edges in a Crafting Table."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_4: &str = "howtoplay.navigation.text.4";
    #[doc = "A Locator Map will show you where you are and what direction you are facing in relation to the Locator Map's origin. It will also show you the location of other players in the same world."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_5: &str = "howtoplay.navigation.text.5";
    #[doc = "A Cartography Table can help you create, expand, copy and even name maps."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_6: &str = "howtoplay.navigation.text.6";
    #[doc = "Place paper into the first slot to craft a Map. If you add a compass into the second slot you can craft a Locator Map. Adding Paper or a blank Map will let you expand or copy your Map."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_7: &str = "howtoplay.navigation.text.7";
    #[doc = "Navigation Techniques"]
    pub const HOWTOPLAY_NAVIGATION_HEADER_2: &str = "howtoplay.navigation.header.2";
    #[doc = "Try to watch for landmarks as you explore. The more you play on a world, the more you will be able to remember where you are. Another good trick is to place Torches as you go so that you may find your way back home."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_8: &str = "howtoplay.navigation.text.8";
    #[doc = "The sun can also tell you what direction you are facing. Remember: the sun rises in the east and sets in the west!"]
    pub const HOWTOPLAY_NAVIGATION_TEXT_9: &str = "howtoplay.navigation.text.9";
    #[doc = "Explorer Maps"]
    pub const HOWTOPLAY_NAVIGATION_HEADER_3: &str = "howtoplay.navigation.header.3";
    #[doc = "There are several places for you to explore. Find a village and look for a Cartographer. They will trade you Explorer Maps that will lead you to strange places very far away."]
    pub const HOWTOPLAY_NAVIGATION_TEXT_10: &str = "howtoplay.navigation.text.10";
