    #[doc = "In Minecraft, the sun rises and sets as you adventure in your world. As the sun sets, you must take precautions. There are many dangers at night!"]
    pub const HOWTOPLAY_NIGHTFALL_TEXT_1: &str = "howtoplay.nightfall.text.1";
    #[doc = "Take Shelter"]
    pub const HOWTOPLAY_NIGHTFALL_HEADER_1: &str = "howtoplay.nightfall.header.1";
    #[doc = "If you have not already, you will need a place to take shelter from the dark and what lurks within it. This can be as simple as a hole in the side of a hill or a small cabin in the forest."]
    pub const HOWTOPLAY_NIGHTFALL_TEXT_2: &str = "howtoplay.nightfall.text.2";
    #[doc = "Be sure to block off all entrances, you may want to use a door so you can go in and out. If you have made a bed this is a good place to put it along with your Crafting Table and Furnace."]
    pub const HOWTOPLAY_NIGHTFALL_TEXT_3: &str = "howtoplay.nightfall.text.3";
    #[doc = "Also be sure to light up the area with torches, it may save your life."]
    pub const HOWTOPLAY_NIGHTFALL_TEXT_4: &str = "howtoplay.nightfall.text.4";
