    #[doc = "Pets"]
    pub const HOWTOPLAY_PETS: &str = "howtoplay.pets";
    #[doc = "Befriending Pets"]
    pub const HOWTOPLAY_PETS_HEADER_1: &str = "howtoplay.pets.header.1";
    #[doc = "There are several mobs in Minecraft that you can tame and make your pet. Each can be tamed by giving them an item that they like. Once tamed you can have them stay by pressing :_input_key.use: while looking at them."]
    pub const HOWTOPLAY_PETS_TEXT_1_NOTTOUCH: &str = "howtoplay.pets.text.1.notTouch";
    #[doc = "There are several mobs in Minecraft that you can tame and make your pet. Each can be tamed by giving them an item that they like. Once tamed you can have them stay by tapping the Sit Button."]
    pub const HOWTOPLAY_PETS_TEXT_1_TOUCH: &str = "howtoplay.pets.text.1.touch";
    #[doc = "Wolves"]
    pub const HOWTOPLAY_PETS_HEADER_2: &str = "howtoplay.pets.header.2";
    #[doc = "Wolves are a neutral mob that hunt in the colder climates. They will attack Rabbits, Skeletons, and Sheep but run away from Llamas. They won't attack you unless you provoke them. You can tame them by giving them Bones."]
    pub const HOWTOPLAY_PETS_TEXT_2: &str = "howtoplay.pets.text.2";
    #[doc = "Cats"]
    pub const HOWTOPLAY_PETS_HEADER_3: &str = "howtoplay.pets.header.3";
    #[doc = "Cats are a neutral mob that can be found in villages. They will attack Rabbits and Baby Turtles. They will also keep Phantoms and Creepers away. They will try to run from you so taming them can be tough. They like fish so give them Raw Cod or Salmon to tame them."]
    pub const HOWTOPLAY_PETS_TEXT_3: &str = "howtoplay.pets.text.3";
    #[doc = "Parrots"]
    pub const HOWTOPLAY_PETS_HEADER_4: &str = "howtoplay.pets.header.4";
    #[doc = "Parrots are a passive mob that live in the Jungle. They will imitate any other mob in the area. Seeds are their favorite, give them a few to tame them. Parrots will also sit on your shoulder... Yes, you can have more than one up there."]
    pub const HOWTOPLAY_PETS_TEXT_4: &str = "howtoplay.pets.text.4";
    #[doc = "Raids"]
    pub const HOWTOPLAY_RAIDS: &str = "howtoplay.raids";
    #[doc = "While exploring the world you may encounter a Pillager encampment or patrol. Pillagers are always looking for villages to raid. Taking their Banners will get their attention, and they may choose to attack a nearby village."]
    pub const HOWTOPLAY_RAIDS_TEXT_1: &str = "howtoplay.raids.text.1";
    #[doc = "Be sure to defend your village, the attack will stop if you defeat all the raiders."]
    pub const HOWTOPLAY_RAIDS_TEXT_2: &str = "howtoplay.raids.text.2";
    #[doc = "I Need A Hero"]
    pub const HOWTOPLAY_RAIDS_HEADER_1: &str = "howtoplay.raids.header.1";
    #[doc = "Villagers will most likely be very grateful that you have saved them from the raiders. Be sure to check back with them, you might get a good deal."]
    pub const HOWTOPLAY_RAIDS_TEXT_3: &str = "howtoplay.raids.text.3";
    #[doc = "Ranching"]
    pub const HOWTOPLAY_RANCHING: &str = "howtoplay.ranching";
    #[doc = "In Minecraft, you can have your own ranch filled with livestock! Ranching provides lots of resources such as wool, eggs, and raw meat."]
    pub const HOWTOPLAY_RANCHING_TEXT_1: &str = "howtoplay.ranching.text.1";
    #[doc = "Growing Your Herd"]
    pub const HOWTOPLAY_RANCHING_HEADER_1: &str = "howtoplay.ranching.header.1";
    #[doc = "In order to keep your livestock growing, you have to make baby animals. Adult animals must enter Love Mode for this to happen. Feed the animals their preferred food to get them to enter Love Mode."]
    pub const HOWTOPLAY_RANCHING_TEXT_2: &str = "howtoplay.ranching.text.2";
    #[doc = "When two like animals are nearby and in Love Mode, they will kiss for a moment and then a baby animal will appear! The baby animal will stay with their parents until they grow into an adult. After having a baby, adult animals must wait 1 minute before entering Love Mode."]
    pub const HOWTOPLAY_RANCHING_TEXT_3: &str = "howtoplay.ranching.text.3";
    #[doc = "What Do Mobs Eat?"]
    pub const HOWTOPLAY_RANCHING_HEADER_2: &str = "howtoplay.ranching.header.2";
    #[doc = "Cows, mooshrooms, and sheep all eat Wheat. Pigs can eat Carrots or Beetroot. Chickens love Seeds of any kinds. Rabbits will eat Carrots, Golden Carrots, or Dandelions. Ocelots enjoy Raw Cod or Salmon. Wolves like to eat any kind of meat."]
    pub const HOWTOPLAY_RANCHING_TEXT_4: &str = "howtoplay.ranching.text.4";
    #[doc = "Animals will follow you when you hold their desired food item. This will help you lead them to your ranch or another animal."]
    pub const HOWTOPLAY_RANCHING_TEXT_5: &str = "howtoplay.ranching.text.5";
