    #[doc = "Scaffolding can help you create huge structures safely! You can walk inside scaffolding and stand on it. If you have a column of scaffolding you can go upward by standing in the scaffolding and pressing :_input_key.jump:. If you want to travel downward you can press and hold :_input_key.sneak:."]
