    #[doc = "Structure Blocks"]
    pub const HOWTOPLAY_STRUCTUREBLOCKS: &str = "howtoplay.structureBlocks";
    #[doc = "Structure Blocks give creators the ability to copy and save out sections of their world into structures. Saved structures can then be pasted back into the world."]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_TEXT_1: &str = "howtoplay.structureBlocks.text.1";
    #[doc = "How to Obtain"]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_HEADER_1: &str = "howtoplay.structureBlocks.header.1";
    #[doc = "To get a Structure Block you must use the /give slash command. To use a Structure Block, you must have Operator permissions."]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_TEXT_2: &str = "howtoplay.structureBlocks.text.2";
    #[doc = "Modes"]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_HEADER_2: &str = "howtoplay.structureBlocks.header.2";
    #[doc = "Structure Blocks have 4 modes that can be switched between with the Mode dropdown: Save, Load, Corner, and 3D Export."]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_TEXT_3: &str = "howtoplay.structureBlocks.text.3";
