    pub const HOWTOPLAY_STRUCTUREBLOCKS_TEXT_5: &str = "howtoplay.structureBlocks.text.5";
    #[doc = "Corner mode is used with save mode's detect button to automatically set the area you want to save. See the Corner Mode section below for more details."]
