    pub const HOWTOPLAY_STRUCTUREBLOCKS_TEXT_10: &str = "howtoplay.structureBlocks.text.10";
    #[doc = "Integrity and Seed"]
    pub const HOWTOPLAY_STRUCTUREBLOCKS_HEADER_5: &str = "howtoplay.structureBlocks.header.5";
